GameDressStore = {}
GameDressStore.Status = {
    LOCK = 0,
    NOT_GET = 1,
    NEW = 2,
    HAS_GET = 3,
    HAS_USE = 4,
    JUST_BUY = 5,
}

function GameDressStore:sendUpdateStoreDressData(player, data)
    if BaseMain:getGameType() == "g1046" then
        GamePacketSender:sendBedWarDressStoreData(player.rakssid, json.encode(data))
    end
end

function GameDressStore:initDressStoreData(player)
    for _, dress in pairs(DressConfig.Dress) do
        if dress.HasGet then
            local data = {
                Id = dress.Id,
                Status = GameDressStore.Status.HAS_GET,
                Chip = 0,
                In_Trial = false,
            }
            if player.equip_dress[tostring(dress.OldItemId)] == nil then
                data.Status = GameDressStore.Status.HAS_USE
                player:addItemOrEquipItem(dress.ItemId)
                player.equip_dress[tostring(dress.OldItemId)] = dress.ItemId
            end
            table.insert(player.dress, data)
        end
    end
end

function GameDressStore:getPlayerDressInfo(player, dress)
    for _, player_dress in pairs(player.dress) do
        if player_dress.Id == dress.Id then
            local data = {
                Id = player_dress.Id,
            }
            if player_dress.Status == GameDressStore.Status.LOCK and player.level >= dress.UnlockLevel then
                player_dress.Status = GameDressStore.Status.NEW
            end
            data.Status = player_dress.Status
            if player_dress.Chip > 0 then
                data.Chip = player_dress.Chip
            end
            if player_dress.In_Trial == nil then
                player_dress.In_Trial = false
            end
            return data
        end
    end

    local data = {
        Id = dress.Id,
        Status = GameDressStore.Status.NEW
    }

    if dress.UnlockLevel > player.level then
        data.Status = GameDressStore.Status.LOCK
    end
    return data
end

function GameDressStore:syncDressStoreData(player)
    if not DbUtil:IsGetAllDataFinished(player) then
        return
    end
    local dress_data = {}
    for _, dress in pairs(DressConfig.Dress) do
        table.insert(dress_data, GameDressStore:getPlayerDressInfo(player, dress))
    end
    GameDressStore:sendUpdateStoreDressData(player, dress_data)
end

function GameDressStore:onFirstShowStoreDress(player, id)
    for _, player_dress in pairs(player.dress) do
        if player_dress.Id == id then
            if player_dress.Status == GameDressStore.Status.HAS_GET or player_dress.Status == GameDressStore.Status.HAS_USE then
                return
            end
            player_dress.Status = GameDressStore.Status.NOT_GET
            return
        end
    end
    local dress = {
        Id = id,
        Status = GameDressStore.Status.NOT_GET,
        Chip = 0,
        In_Trial = false,
    }
    table.insert(player.dress, dress)
end

function GameDressStore:onUseStoreDress(player, id, isJustBuy)
    local config = DressConfig:getDress(id)
    if not config then
        return
    end
    local data = {}
    for _, dress in pairs(player.dress) do
        if dress.Status == GameDressStore.Status.HAS_USE then
            local c_config = DressConfig:getDress(dress.Id)
            if c_config ~= nil then
                if c_config.OldItemId == config.OldItemId then
                    dress.Status = GameDressStore.Status.HAS_GET
                    table.insert(data, {
                        Id = c_config.Id,
                        Status = GameDressStore.Status.HAS_GET
                    })

                    player.equip_dress[tostring(config.OldItemId)] = nil
                    player:removeItem(c_config.ItemId, 1)
                end
            end
        end
    end

    for _, dress in pairs(player.dress) do
        if dress.Id == id then
            if dress.Status == GameDressStore.Status.HAS_GET then
                dress.Status = GameDressStore.Status.HAS_USE
                player:addItemOrEquipItem(config.ItemId)
                local info = {
                    Id = dress.Id,
                    Status = GameDressStore.Status.HAS_USE
                }
                if isJustBuy then
                    info.Status = GameDressStore.Status.JUST_BUY
                end
                table.insert(data, info)
                player.equip_dress[tostring(config.OldItemId)] = config.ItemId
            end
            break
        end
    end
    GameDressStore:sendUpdateStoreDressData(player, data)
end

function GameDressStore:onBuyStoreDress(player, id)
    local config = DressConfig:getDress(id)
    if not config then
        return
    end

    local dress
    for _, player_dress in pairs(player.dress) do
        if player_dress.Id == id then
            dress = player_dress
            break
        end
    end
    if dress == nil then
        dress = {
            Id = config.Id,
            Status = GameDressStore.Status.NOT_GET,
            Chip = 0,
            In_Trial = false,
        }
        table.insert(player.dress, dress)
    end

    if dress.Status == GameDressStore.Status.HAS_GET or dress.Status == GameDressStore.Status.HAS_USE then
        return
    end
    if not MoneyUtil:checkHasMoney(player, config.PriceType, config.Price, dress.Chip) then
        if config.PriceType == Define.Money.CHIP and dress.Chip < config.Price then
            local lackNum = config.Price - dress.Chip
            local Lack = { lackNum = lackNum, Id = config.Id }
            if BaseMain:getGameType() == "g1046" then
                GamePacketSender:sendBedWarLackChip(player.rakssid, json.encode(Lack))
            end
        end
        return
    end

    if config.PriceType == Define.Money.DIAMOND then
        player:consumeDiamonds(799 + config.Id, config.Price, Define.BuyDress .. "#" .. config.Id)
        return
    end

    if config.PriceType == Define.Money.CHIP then
        for _, player_dress in pairs(player.dress) do
            if player_dress.Id == id then
                player_dress.Chip = player_dress.Chip - config.Price
                player_dress.In_Trial = false
                local data = {}
                table.insert(data, {
                    Id = player_dress.Id,
                    Chip = player_dress.Chip,
                    Status = GameDressStore.Status.HAS_GET
                })

                GameDressStore:sendUpdateStoreDressData(player, data)
                GameDressStore:onBuyStoreDressSuccess(player, id)
                break
            end
        end
        return
    end
end

function GameDressStore:onBuyStoreDressSuccess(player, id)
    for _, player_dress in pairs(player.dress) do
        if player_dress.Id == id then
            player_dress.Status = GameDressStore.Status.HAS_GET
            break
        end
    end
    GameDressStore:onUseStoreDress(player, id, true)
end

function GameDressStore:onUnloadStoreDress(player, id)
    local config = DressConfig:getDress(id)
    if not config then
        return
    end

    local data = {}
    for _, dress in pairs(player.dress) do
        if dress.Status == GameDressStore.Status.HAS_USE then
            local c_config = DressConfig:getDress(dress.Id)
            if c_config ~= nil then
                if c_config.OldItemId == config.OldItemId then
                    dress.Status = GameDressStore.Status.HAS_GET
                    table.insert(data, {
                        Id = c_config.Id,
                        Status = GameDressStore.Status.HAS_GET
                    })

                    player.equip_dress[tostring(config.OldItemId)] = nil
                    player:removeItem(config.ItemId, 1)
                end
            end
        end
    end
    GameDressStore:sendUpdateStoreDressData(player, data)
end

function GameDressStore:onPlayerConfirmPayDressChip(player, dressId)
    local config = DressConfig:getDress(dressId)
    if not config or config.UnlockLevel > player.level then
        return
    end
    local haveChip = 0
    for k, curDress in pairs(player.dress) do
        if curDress.Id == dressId then
            haveChip = curDress.Chip
        end
    end
    local lackNum = (config.Price - haveChip) * 2
    if MoneyUtil:checkHasMoney(player, Define.Money.KEY, lackNum, 0) then
        player:subYaoShi(lackNum, "key_DressStore", dressId)
        self:onPlayerBuyDressChip(player, dressId)
    else
        HostApi.sendCustomTip(player.rakssid, "lack_of_key", Define.LackOfKey)
    end
end

function GameDressStore:onPlayerBuyDressChip(player, dressId)
    local config = DressConfig:getDress(dressId)
    if not config then
        return
    end

    for k, curDress in pairs(player.dress) do
        if curDress.Id == dressId then
            curDress.Status = GameDressStore.Status.HAS_GET
            local data = {}
            table.insert(data, curDress)
            self:sendUpdateStoreDressData(player, data)
            self:onUseStoreDress(player, dressId, true)
            return
        end
    end

    local data = {
        Id = dressId,
        Status = GameDressStore.Status.HAS_GET,
        Chip = 0,
        In_Trial = false,
    }
    table.insert(player.dress, data)

    local info = {}
    table.insert(info, data)
    self:sendUpdateStoreDressData(player, info)
    self:onUseStoreDress(player, dressId, true)
end

function GameDressStore:onTrialStoreDress(player, id)
    local config = DressConfig:getDress(id)
    if not config then
        return
    end

    local dress
    for _, player_dress in pairs(player.dress) do
        if player_dress.Id == id then
            dress = player_dress
            break
        end
    end
    if dress == nil then
        dress = {
            Id = config.Id,
            Status = GameDressStore.Status.NOT_GET,
            Chip = 0,
            In_Trial = false,
        }
        table.insert(player.dress, dress)
    end

    if dress.Status == GameDressStore.Status.HAS_GET or dress.Status == GameDressStore.Status.HAS_USE then
        return
    end

    for _, player_dress in pairs(player.dress) do
        if player_dress.Id == id then
            player_dress.In_Trial = true
            local data = {}
            table.insert(data, {
                Id = player_dress.Id,
                Chip = player_dress.Chip,
                Status = GameDressStore.Status.HAS_GET
            })

            GameDressStore:sendUpdateStoreDressData(player, data)
            GameDressStore:onBuyStoreDressSuccess(player, id)
            break
        end
    end
end

function GameDressStore:onTrialStoreDressTimeOut(player, id)
    local config = DressConfig:getDress(id)
    if not config then
        return
    end
    for _, player_dress in pairs(player.dress) do
        if player_dress.Id == id then
            if player_dress.In_Trial == true then
                if player_dress.Status == GameDressStore.Status.HAS_USE then
                    player.equip_dress[tostring(config.OldItemId)] = nil
                end
                player_dress.Status = GameDressStore.Status.NOT_GET
                local data = {}
                table.insert(data, {
                    Id = player_dress.Id,
                    Chip = player_dress.Chip,
                    Status = GameDressStore.Status.NOT_GET,
                })
                GameDressStore:sendUpdateStoreDressData(player, data)
                break
            end
        end
    end
end

return GameDressStore